-- Fix economics AR questions: add assertion + reason to payload

UPDATE med_questions SET payload = payload || '{"assertion": "The Balance of Payments always balances in the accounting sense.", "reason": "Every international transaction involves a debit entry and a corresponding credit entry of equal value (double-entry bookkeeping)."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-accounts-06';
UPDATE med_questions SET payload = payload || '{"assertion": "India''s IT service exports are recorded in the current account of BOP.", "reason": "Services like IT, tourism, and shipping are classified as ''invisible trade'' and are part of the current account."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-accounts-07';
UPDATE med_questions SET payload = payload || '{"assertion": "A current account deficit must always be matched by a capital account surplus of equal magnitude.", "reason": "The Balance of Payments must always balance — any deficit in one account must be offset by a surplus in the other account (including official reserve changes)."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-accounts-08';
UPDATE med_questions SET payload = payload || '{"assertion": "Devaluation and depreciation are essentially the same thing because both result in a fall in the value of the domestic currency.", "reason": "Devaluation is a deliberate policy action under a fixed exchange rate system, while depreciation is a market-driven outcome under a flexible exchange rate system."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-devaluation-06';
UPDATE med_questions SET payload = payload || '{"assertion": "Devaluation of a currency always leads to an immediate improvement in the trade balance.", "reason": "According to the J-curve effect, the trade balance may initially worsen after devaluation before eventually improving."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-devaluation-07';
UPDATE med_questions SET payload = payload || '{"assertion": "Devaluation of a country''s currency increases the real burden of its foreign debt denominated in foreign currency.", "reason": "After devaluation, more units of domestic currency are needed to repay the same amount of foreign currency-denominated debt."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-devaluation-08';
UPDATE med_questions SET payload = payload || '{"assertion": "When Indians import more goods from abroad, the demand for foreign exchange in India increases.", "reason": "To pay for imports, Indian importers need to buy foreign currency by selling Indian rupees in the foreign exchange market."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-forex-market-06';
UPDATE med_questions SET payload = payload || '{"assertion": "An increase in the supply of foreign exchange in India will lead to an appreciation of the Indian rupee.", "reason": "When supply of foreign exchange increases, there is excess supply of foreign currency at the prevailing rate, which pushes down the price of foreign currency in terms of rupees."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-forex-market-07';
UPDATE med_questions SET payload = payload || '{"assertion": "Speculation in the forex market can cause exchange rate fluctuations even without changes in trade or investment flows.", "reason": "Speculators buy foreign currency when they expect it to appreciate and sell when they expect it to depreciate, and these actions themselves influence the exchange rate."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-forex-market-08';
UPDATE med_questions SET payload = payload || '{"assertion": "Under a fixed exchange rate system, the central bank needs to maintain large foreign exchange reserves.", "reason": "The central bank must buy or sell foreign currency in the market to maintain the exchange rate at the officially fixed level."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-forex-rate-06';
UPDATE med_questions SET payload = payload || '{"assertion": "A flexible exchange rate system always leads to stable and predictable exchange rates.", "reason": "Under a flexible exchange rate system, the exchange rate is determined by market forces of demand and supply."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-forex-rate-07';
UPDATE med_questions SET payload = payload || '{"assertion": "India follows a managed floating exchange rate system since 1993.", "reason": "Under managed floating, the exchange rate is determined entirely by the Reserve Bank of India without any role of market forces."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-forex-rate-08';
UPDATE med_questions SET payload = payload || '{"assertion": "Balance of Trade is a narrower concept than Balance of Payments.", "reason": "Balance of Trade includes only trade in goods, while Balance of Payments includes goods, services, income, transfers, and capital flows."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-trade-06';
UPDATE med_questions SET payload = payload || '{"assertion": "India has consistently run a merchandise trade deficit for decades.", "reason": "India''s dependence on crude oil imports, which constitute a large share of its import bill, makes its import expenditure persistently higher than its export earnings."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-trade-07';
UPDATE med_questions SET payload = payload || '{"assertion": "A trade deficit is not necessarily harmful for an economy.", "reason": "A trade deficit may be financed by foreign investment inflows that bring technology, create jobs, and increase productive capacity."}'::jsonb WHERE payload->>'question_id' = 'eco-bop-trade-08';
UPDATE med_questions SET payload = payload || '{"assertion": "The budget line is a straight line.", "reason": "The prices of goods are assumed to be constant regardless of the quantity purchased."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-budget-line-06';
UPDATE med_questions SET payload = payload || '{"assertion": "If the prices of both goods double while income also doubles, the budget line remains unchanged.", "reason": "The budget line depends on the ratio of prices and the real purchasing power, both of which remain unchanged when prices and income change proportionally."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-budget-line-07';
UPDATE med_questions SET payload = payload || '{"assertion": "At the point of consumer equilibrium, the budget line is tangent to an indifference curve.", "reason": "Tangency ensures that the slope of the budget line (P_x/P_y) equals the slope of the indifference curve (MRS_xy), meaning the consumer''s subjective trade-off rate equals the market''s objective exchange rate."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-budget-line-08';
UPDATE med_questions SET payload = payload || '{"assertion": "Salt has highly inelastic demand.", "reason": "Salt is a necessity with no close substitutes and takes a very small proportion of consumer income."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-elasticity-of-demand-06';
UPDATE med_questions SET payload = payload || '{"assertion": "A perfectly vertical demand curve has price elasticity of demand equal to zero.", "reason": "A vertical demand curve means that quantity demanded remains the same regardless of the price level."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-elasticity-of-demand-07';
UPDATE med_questions SET payload = payload || '{"assertion": "On a linear (straight-line) demand curve, elasticity varies from infinity at the y-axis intercept to zero at the x-axis intercept.", "reason": "Although the slope of a linear demand curve is constant, elasticity depends on the ratio of P/Q, which changes at every point along the curve."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-elasticity-of-demand-08';
UPDATE med_questions SET payload = payload || '{"assertion": "Indifference curves slope downward from left to right.", "reason": "To maintain the same level of satisfaction, if consumption of one good increases, consumption of the other must decrease."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-indifference-curves-06';
UPDATE med_questions SET payload = payload || '{"assertion": "The indifference curve approach is superior to the cardinal utility approach because it does not require cardinal measurement of utility.", "reason": "The indifference curve approach uses ordinal ranking of preferences, which only requires consumers to rank bundles without assigning exact utility numbers."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-indifference-curves-07';
UPDATE med_questions SET payload = payload || '{"assertion": "For perfect complements (like left and right shoes), indifference curves are L-shaped (right-angled).", "reason": "Perfect complements are always consumed in a fixed ratio, so having extra units of only one good does not increase utility."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-indifference-curves-08';
UPDATE med_questions SET payload = payload || '{"assertion": "The demand schedule shows the inverse relationship between price and quantity demanded.", "reason": "A demand schedule is a tabular representation of the law of demand."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-law-of-demand-06';
UPDATE med_questions SET payload = payload || '{"assertion": "An increase in consumer income causes a rightward shift of the demand curve for a normal good.", "reason": "When income rises, consumers can afford to buy more of a normal good at every price level."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-law-of-demand-07';
UPDATE med_questions SET payload = payload || '{"assertion": "Veblen goods have an upward-sloping demand curve because consumers buy more when prices rise.", "reason": "Veblen goods are status symbols where higher price signals higher prestige and exclusivity."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-law-of-demand-08';
UPDATE med_questions SET payload = payload || '{"assertion": "The demand curve slopes downward from left to right.", "reason": "As the price of a good falls, a consumer buys more because the marginal utility of money rises relative to the good."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-utility-approach-06';
UPDATE med_questions SET payload = payload || '{"assertion": "A rational consumer will not consume a good beyond the point where marginal utility becomes negative.", "reason": "Consuming beyond the point of zero marginal utility leads to a decrease in total utility."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-utility-approach-07';
UPDATE med_questions SET payload = payload || '{"assertion": "The cardinal utility approach is considered less realistic than the ordinal utility approach.", "reason": "In practice, consumers cannot assign exact numerical values to the satisfaction they derive from goods."}'::jsonb WHERE payload->>'question_id' = 'eco-cd-utility-approach-08';
UPDATE med_questions SET payload = payload || '{"assertion": "China''s GDP growth rate has been consistently higher than India''s since the 1980s.", "reason": "China initiated its economic reforms in 1978, more than a decade before India''s 1991 reforms, giving it a significant head start in liberalising its economy."}'::jsonb WHERE payload->>'question_id' = 'eco-de-india-china-06';
