UPDATE med_questions SET payload = payload || '{"assertion": "China''s One-Child Policy successfully reduced the population growth rate but created serious demographic challenges.", "reason": "The One-Child Policy led to a rapidly ageing population, a declining workforce, and a severely skewed sex ratio due to preference for male children."}'::jsonb WHERE payload->>'question_id' = 'eco-de-india-china-08';
