UPDATE med_questions SET payload = payload || '{"assertion": "India performs better than China and Pakistan on liberty indicators such as political freedom, press freedom, and civil liberties.", "reason": "India has consistently maintained a democratic political system with free elections, an independent judiciary, and a free press since its independence."}'::jsonb WHERE payload->>'question_id' = 'eco-de-indicators-07';
