UPDATE med_questions SET payload = payload || '{"assertion": "China''s one-child policy, while effective in controlling population growth, has created long-term demographic challenges.", "reason": "The one-child policy has led to a rapidly ageing population and a shrinking workforce, which threatens China''s future economic growth prospects."}'::jsonb WHERE payload->>'question_id' = 'eco-de-lessons-07';
