UPDATE med_questions SET payload = payload || '{"assertion": "India followed a mixed economy model after independence, combining features of both capitalism and socialism.", "reason": "India''s five-year plans gave the public sector a leading role in heavy industries while allowing the private sector to operate in consumer goods and light industries."}'::jsonb WHERE payload->>'question_id' = 'eco-de-strategies-08';
